1	import { useState } from "react";
2	import { useEventTrade } from "@/lib/query/hooks";
3	import { useSession } from "@/features/session/context";
4	import type { Market, AssetDelta } from "@/lib/api/types";
5	
6	function TradeReceipt({ delta }: { delta: AssetDelta }) {
7	  const impact = delta.impactScore;
8	  const impactColor = impact > 0.5 ? "var(--color-danger)" : impact > 0.2 ? "var(--color-warning, orange)" : "var(--color-text-muted)";
9	
10	  return (
11	    <div style={{ display: "grid", gridTemplateColumns: "repeat(4, 1fr)", gap: "var(--space-sm)", marginTop: "var(--space-xs)", fontSize: "0.75rem" }}>
12	      <div>
13	        <div style={{ color: "var(--color-text-muted)" }}>Before</div>
14	        <div style={{ fontFamily: "var(--font-mono)" }}>{delta.beforeMinAsset.toFixed(2)}</div>
15	      </div>
16	      <div>
17	        <div style={{ color: "var(--color-text-muted)" }}>After</div>
18	        <div style={{ fontFamily: "var(--font-mono)" }}>{delta.afterMinAsset.toFixed(2)}</div>
19	      </div>
20	      <div>
21	        <div style={{ color: "var(--color-text-muted)" }}>Impact</div>
22	        <div style={{ fontFamily: "var(--font-mono)", color: impactColor }}>{(impact * 100).toFixed(1)}%</div>
23	      </div>
24	      <div>
25	        <div style={{ color: "var(--color-text-muted)" }}>Limit</div>
26	        <div style={{ fontFamily: "var(--font-mono)" }}>{delta.riskLimit.toFixed(2)}</div>
27	      </div>
28	    </div>
29	  );
30	}
31	
32	interface Props {
33	  market: Market;
34	}
35	
36	export function EventTradePanel({ market }: Props) {
37	  const { session, isConfigured } = useSession();
38	  const mutation = useEventTrade(market.id);
39	  const [selectedOutcome, setSelectedOutcome] = useState<string>("");
40	  const [side, setSide] = useState<"buy" | "sell">("buy");
41	
42	  if (market.status !== "active") return null;
43	  if (!isConfigured) return null;
44	
45	  const currentPrice = selectedOutcome ? (market.marginals[selectedOutcome] ?? 0) : 0;
46	
47	  const handleTrade = () => {
48	    if (!selectedOutcome) return;
49	
50	    mutation.mutate({
51	      payload: {
52	        accountId: session.accountId,
53	        formula: [[{
54	          variableId: market.id,
55	          outcomeId: selectedOutcome,
56	          negated: false,
57	        }]],
58	        side,
59	        idempotencyKey: crypto.randomUUID(),
60	      },
61	      session,
62	    });
63	  };
64	
65	  return (
66	    <div style={panelStyle}>
67	      <div style={{ fontSize: "0.85rem", fontWeight: 600, marginBottom: "var(--space-sm)" }}>
68	        Quick Trade
