export interface OrderResponse {
  command: {
    commandId: string;
    marketId: string;
    accountId: string;
    type: string;
    submittedAt: string;
  };
  order: {
    orderId: string;
    commandId: string;
    marketId: string;
    type: string;
  };
  assetDelta: AssetDelta;
  terminalOutcome: TerminalOutcome;
  meta: Meta;
}

export interface ApiError {
  error: {
    code: string;
    message: string;
    details?: Record<string, unknown>;
  };
  meta: Meta;
}

export interface Meta {
  apiVersion: string;
  timestamp: string;
  filters?: {
    status?: MarketStatus | null;
    sort?: MarketListSort | null;
    q?: string | null;
  };
}

export interface ProbabilityEditPayload {
  accountId: string;
  variableId: string;
  target: {
    kind: "marginal";
    outcomeId: string;
    probability: number;
  };
  context: Array<{ variableId: string; outcomeId: string }>;
  idempotencyKey?: string;
}

